#include <stdio.h>
int min(int a, int b) { return a < b ? a : b; }
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int dp[n][3];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < 3; j++) {
            dp[i][j] = -1;
        }
    }
    int solve(int i, int j, int arr[], int n, int dp[][]) {
        if (i == n) return 0;
        if (dp[i][j] != -1) return dp[i][j];
        int ans = 1e9;
        for (int k = 0; k < 3; k++) {
            if (k != j) {
                ans = min(ans, solve(i + 1, k, arr, n, dp) + (arr[i] != k + 1));
            }
        }
        return dp[i][j] = ans;
    }
    printf("%d\n", solve(0, 3, arr, n, dp));
    return 0;
}

