import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] arr = new int[n];
        for (int i = 0; i < n; i++) {
            arr[i] = sc.nextInt();
        }
        int[][] dp = new int[n][3];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 3; j++) {
                dp[i][j] = -1;
            }
        }
        System.out.println(solve(0, 3, arr, n, dp));
    }
    public static int solve(int i, int j, int[] arr, int n, int[][] dp) {
        if (i == n) return 0;
        if (dp[i][j] != -1) return dp[i][j];
        int ans = (int) 1e9;
        for (int k = 0; k < 3; k++) {
            if (k != j) {
                ans = Math.min(ans, solve(i + 1, k, arr, n, dp) + (arr[i] != k + 1));
            }
        }
        return dp[i][j] = ans;
    }
