function solve(i, j, arr, n, dp) {
    if (i == n) return 0;
    if (dp[i][j] != -1) return dp[i][j];
    let ans = 1e9;
    for (let k = 0; k < 3; k++) {
        if (k != j) {
            ans = Math.min(ans, solve(i + 1, k, arr, n, dp) + (arr[i] != k + 1));
        }
    }
    return dp[i][j] = ans;
}
function main() {
    let input = readline().split(' ');
    let n = parseInt(input[0]);
    let arr = readline().split(' ').map(x => parseInt(x));
    let dp = Array(n).fill().map(() => Array(3).fill(-1));
    print(solve(0, 3, arr, n, dp));
}
